import type {AsChild} from '@/lib/types';
import type * as React from 'react';

import {cn} from '@/lib/utils';

import {cva, type VariantProps} from 'class-variance-authority';
import {Slot} from 'radix-ui';

const iconButtonVariants = cva(
  'relative inline-flex shrink-0 items-center justify-center rounded-sm transition-colors outline-none select-none disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:shrink-0',
  {
    variants: {
      variant: {
        ghost:
          'text-muted-foreground hover:bg-muted hover:text-foreground focus-visible:ring-1 focus-visible:ring-ring',
        outline:
          'border border-border text-muted-foreground hover:bg-muted hover:text-foreground focus-visible:ring-1 focus-visible:ring-ring',
        destructive:
          'text-muted-foreground hover:bg-destructive/10 hover:text-destructive focus-visible:ring-1 focus-visible:ring-destructive',
      },
      size: {
        xs: "size-4 after:absolute after:-inset-1.5 [&_svg:not([class*='size-'])]:size-3",
        sm: "size-5 after:absolute after:-inset-1 [&_svg:not([class*='size-'])]:size-3.5",
        md: "size-6 after:absolute after:-inset-0.5 [&_svg:not([class*='size-'])]:size-4",
        lg: "size-8 [&_svg:not([class*='size-'])]:size-4",
      },
    },
    defaultVariants: {
      variant: 'ghost',
      size: 'sm',
    },
  }
);

type IconButtonProps = React.ComponentProps<'button'> &
  AsChild & {
    /**
     * The visual style of the icon button.
     *
     * @default "ghost"
     */
    variant?: VariantProps<typeof iconButtonVariants>['variant'];
    /**
     * The size of the icon button. Visual size matches the prop name;
     * xs/sm/md extend the hit area with an invisible `::after` pseudo-element
     * to meet the 24px WCAG 2.5.8 target size minimum.
     *
     * | Size | Visual | Hit area | Icon |
     * |------|--------|----------|------|
     * | xs   | 16px   | 28px     | 12px |
     * | sm   | 20px   | 28px     | 14px |
     * | md   | 24px   | 28px     | 16px |
     * | lg   | 32px   | 32px     | 16px |
     *
     * @default "sm"
     */
    size?: VariantProps<typeof iconButtonVariants>['size'];
  };

/**
 * A compact icon-only button for dense UI chrome: sidebar row actions,
 * inspector close, topology drill-in, session delete.
 *
 * Smaller than `<Button size="icon-xs">` (24px). The visual footprint is
 * 16-32px but the hit area is always >= 24px via an invisible `::after`
 * pseudo-element on the three smaller sizes.
 *
 * Always requires `aria-label` (or `aria-labelledby`) since there is no
 * visible text content.
 *
 * ### Example Usage
 *
 * ```tsx
 * <IconButton size="xs" aria-label="Delete session">
 *   <XIcon />
 * </IconButton>
 *
 * <IconButton variant="destructive" aria-label="Remove container">
 *   <Trash2Icon />
 * </IconButton>
 * ```
 *
 * ### Accessibility (WCAG 2.2 AA)
 *
 * @wcag 1.4.3 Contrast (Minimum) — icon inherits `currentColor` from variant token; all variants meet 4.5:1.
 * @wcag 2.1.1 Keyboard — native `<button>` element, focusable and activated by Enter/Space.
 * @wcag 2.4.7 Focus Visible — 1px ring using `ring-ring` token, visible in light, dark, and high-contrast modes.
 * @wcag 2.5.8 Target Size (Minimum) — `::after` pseudo-element extends hit area to >= 24px on xs/sm/md sizes.
 * @wcag 4.1.2 Name, Role, Value — requires `aria-label` for accessible name; no visible text content.
 */
function IconButton({
  className,
  variant = 'ghost',
  size = 'sm',
  asChild = false,
  ...props
}: IconButtonProps) {
  const Comp = asChild ? Slot.Root : 'button';

  return (
    <Comp
      type="button"
      data-slot="icon-button"
      data-variant={variant}
      data-size={size}
      className={cn(iconButtonVariants({variant, size, className}))}
      {...props}
    />
  );
}

export {IconButton, iconButtonVariants};
export type {IconButtonProps};
